const apiKey = '__YOUTUBE_API_KEY__';
const playlistId = 'PL3lTxqA4f3PhmxU9HEd1Lk17ZoeP4bhfz';
const maxPages = 100;
const pageSize = 50;
const allVideos = [];
let pageToken = '';
let pageCount = 0;

function sqlQuote(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

while (pageCount < maxPages) {
  const pageTokenPart = pageToken ? `&pageToken=${encodeURIComponent(pageToken)}` : '';
  const url = `https://www.googleapis.com/youtube/v3/playlistItems?key=${encodeURIComponent(apiKey)}&playlistId=${encodeURIComponent(playlistId)}&part=snippet&maxResults=${pageSize}${pageTokenPart}`;
  const httpResponse = await fetch(url, { method: 'GET' });
  if (!httpResponse.ok) {
    const body = await httpResponse.text();
    throw new Error(`YouTube playlist fetch failed: ${httpResponse.status} ${body}`);
  }
  const response = await httpResponse.json();
  const items = Array.isArray(response.items) ? response.items : [];

  for (const entry of items) {
    const snippet = entry?.snippet || {};
    const videoId = snippet?.resourceId?.videoId;
    if (!videoId) continue;

    const thumbnails = snippet.thumbnails || {};
    const thumbnail = thumbnails.maxres?.url || thumbnails.high?.url || thumbnails.medium?.url || thumbnails.default?.url || '';
    const videoUrl = `https://www.youtube.com/watch?v=${videoId}`;
    const normalized = {
      video_id: String(videoId),
      playlist_id: playlistId,
      title: String(snippet.title || ''),
      description: String(snippet.description || ''),
      thumbnail,
      youtube_channel: String(snippet.videoOwnerChannelTitle || snippet.channelTitle || ''),
      published_at: String(snippet.publishedAt || ''),
      video_url: videoUrl,
      backfill_page: pageCount + 1
    };

    allVideos.push({
      json: {
        ...normalized,
        sql_video_id: sqlQuote(normalized.video_id),
        sql_playlist_id: sqlQuote(normalized.playlist_id),
        sql_title: sqlQuote(normalized.title),
        sql_description: sqlQuote(normalized.description),
        sql_thumbnail: sqlQuote(normalized.thumbnail),
        sql_youtube_channel: sqlQuote(normalized.youtube_channel),
        sql_published_at: sqlQuote(normalized.published_at),
        sql_video_url: sqlQuote(normalized.video_url)
      }
    });
  }

  pageCount += 1;
  pageToken = response.nextPageToken || '';
  if (!pageToken) break;
}

return allVideos;
